int nCondInit(nCond *c, void *ptr) {
  nth_initQueue(&c->wq);
  c->m= NULL;
  return 0;
}

int nCondDestroy(nCond *c) {
  return 0;
}

void nLock(nMutex *m) {
  START_CRITICAL

  nThread thisTh= nSelf();
  if (m->ownerTh==NULL && nth_emptyQueue(&m->wq)) {
    m->ownerTh= thisTh;
  }
  else {
    nth_putBack(&m->wq, thisTh);
    suspend(WAIT_LOCK);
    schedule();
  }

  END_CRITICAL
}

void nUnlock(nMutex *m) {
  START_CRITICAL

  if (m->ownerTh!=nSelf())
    nFatalError("nUnlock", "This thread does not own this mutex\n");
  if (nth_emptyQueue(&m->wq))
    m->ownerTh= NULL;
  else {
    nThread w= nth_getFront(&m->wq);
    m->ownerTh= w;
    setReady(w);
    schedule();
  }

  END_CRITICAL
}

void nCondWait(nCond *c, nMutex *m) {
  START_CRITICAL

  nThread thisTh= nSelf();
  DBG(
    if (m->ownerTh!=thisTh)
      nFatalError("nCondWait", "This thread does not own this mutex\n");
    if (c->m!=NULL && c->m!=m)
      nFatalError("nCondWait", "The mutex is not the same registered before\n");
  );
  c->m= m;
  nth_putBack(&c->wq, thisTh);
  suspend(WAIT_COND);
  if (nth_emptyQueue(&m->wq))
    m->ownerTh= NULL;
  else {
    nThread w= nth_getFront(&m->wq);
    m->ownerTh= w;
    setReady(w);
  }
  schedule();

  END_CRITICAL
}

void nCondSignal(nCond *c) {
  START_CRITICAL

  nThread w= nth_getFront(&c->wq);
  if (w!=NULL) {
    nMutex *m= c->m;
    if (m!=NULL) {
      if (m->ownerTh!=nSelf())
        nFatalError("nCondSignal", "This thread does not own this mutex\n");
      nth_putBack(&m->wq, w);
    }
  }

  END_CRITICAL
}

void nCondBroadcast(nCond *c) {
  START_CRITICAL

  // move all threads in c->wl to their mutex
  nMutex *m= c->m;
  if (m!=NULL) {
    if (m->ownerTh!=nSelf())
      nFatalError("nCondSignal", "Thread does not own this mutex\n");
    while (!nth_emptyQueue(&c->wq)) {
      nThread w= nth_getFront(&c->wq);
      nth_putBack(&m->wq, w);
    }
  }
  END_CRITICAL
}

#define _XOPEN_SOURCE 500

#include "nthread-impl.h"

/*************************************************************
 * nSend, nReceive y nReply
 *************************************************************/

int nSend(nThread th, void *msg) {
  START_CRITICAL

  if (th->status==WAIT_SEND || th->status==WAIT_SEND_TIMEOUT) {
    if (th->status==WAIT_SEND_TIMEOUT)
      nth_cancelThread(th);
    setReady(th);
  }
  else if (th->status==ZOMBIE)
    nFatalError("nSend", "The receiver is a ZOMBIE thread\n");

  nThread thisTh= nSelf();
  nth_putBack(th->sendQueue, thisTh);
  thisTh->send.msg= msg;
  suspend(WAIT_REPLY);

  schedule();

  int rc= thisTh->send.rc;

  END_CRITICAL

  return rc;
}

void *nReceiveNanos(nThread *pth, long long max_nanos) {
  START_CRITICAL

  nThread thisTh= nSelf();

  if (nth_emptyQueue(thisTh->sendQueue) && max_nanos!=0) {
    if (max_nanos<0)
      suspend(WAIT_SEND);
    else {
      suspend(WAIT_SEND_TIMEOUT);
      nth_programTimer(max_nanos, NULL);
    }
    schedule();
  }
  nThread sendTask= nth_getFront(thisTh->sendQueue);
  if (pth!=NULL)
    *pth= sendTask;
  void *msg= sendTask==NULL ? NULL : sendTask->send.msg;

  END_CRITICAL

  return msg;
}

void *nReceive(nThread *pth, int max_millis) {
  return nReceiveNanos(pth, max_millis*1000000LL);
}

void nReply(nThread th, int rc) {
  START_CRITICAL

  if (th->status!=WAIT_REPLY)
    nFatalError("nReply", "This thread does not wait for a nReply\n");

  th->send.rc= rc;
  setReady(th);
  schedule();

  END_CRITICAL
}

