  plog= &log_e[logIdx++];
  plog->coreIn= nth_coreId(); plog->coreOut= -1;
  plog->start= nth_getCoreNanos(); plog->end= -1;
  plog->sliceIn= -1; plog->sliceOut= -1;
  plog->intr= -1;
