  nth_threadCount++;
  define(nth_threadSet, newTh, newTh);
  makecontext(&newTh->uctx, (void (*)(void))nth_threadInit, 2, startFun, ptr);
  setReady(newTh);

  schedule();

  *pth= newTh;

  END_CRITICAL

  return 0;
}

