#include <nthread-impl.h>
#include "subasta.h"

/*
 * Supuesto: en este workspace la API disponible es la de subasta.h
 * (nOfrecer con 2 parámetros).  Implemento esa interfaz.
 */

typedef struct bid {
  nThread th;
  double offer;
  unsigned long long seq;
  int result;
  struct bid *next;
} Bid;

struct subasta {
  int units;
  int closed;
  double total;
  int unsold;
  unsigned long long nextSeq;
  int waiting;
  Bid *bids;
};

static void insert_bid(struct subasta *s, Bid *b)
{
  Bid **pp = &s->bids;
  while (*pp != NULL) {
    Bid *cur = *pp;
    if (cur->offer > b->offer || (cur->offer == b->offer && cur->seq < b->seq)) {
      pp = &cur->next;
    }
    else {
      break;
    }
  }
  b->next = *pp;
  *pp = b;
  s->waiting++;
}

static Bid *pop_worst(struct subasta *s)
{
  if (s->bids == NULL)
    return NULL;

  Bid *prev = NULL;
  Bid *cur = s->bids;
  while (cur->next != NULL) {
    prev = cur;
    cur = cur->next;
  }

  if (prev == NULL)
    s->bids = NULL;
  else
    prev->next = NULL;

  cur->next = NULL;
  s->waiting--;
  return cur;
}

nSubasta nNuevaSubasta(int n)
{
  START_CRITICAL

  if (n < 0)
    n = 0;

  nSubasta s = malloc(sizeof(*s));
  if (s == NULL)
    nFatalError("nNuevaSubasta", "No hay memoria suficiente\n");

  s->units = n;
  s->closed = FALSE;
  s->total = 0.0;
  s->unsold = n;
  s->nextSeq = 0;
  s->waiting = 0;
  s->bids = NULL;

  END_CRITICAL
  return s;
}

int nOfrecer(nSubasta s, double oferta)
{
  START_CRITICAL

  if (s == NULL || s->closed) {
    END_CRITICAL
    return FALSE;
  }

  nThread th = nSelf();
  if (th->ptr != NULL)
    nFatalError("nOfrecer", "El thread ya tiene una oferta pendiente\n");

  Bid *bid = malloc(sizeof(*bid));
  if (bid == NULL)
    nFatalError("nOfrecer", "No hay memoria suficiente\n");

  bid->th = th;
  bid->offer = oferta;
  bid->seq = s->nextSeq++;
  bid->result = FALSE;
  bid->next = NULL;
  th->ptr = bid;

  insert_bid(s, bid);

  if (s->waiting > s->units) {
    Bid *worst = pop_worst(s);
    if (worst == bid) {
      th->ptr = NULL;
      free(bid);
      END_CRITICAL
      return FALSE;
    }

    worst->result = FALSE;
    setReady(worst->th);
  }

  suspend(WAIT_SUBASTA);
  schedule();

  bid = (Bid *)th->ptr;
  if (bid == NULL)
    nFatalError("nOfrecer", "Estado inconsistente al reanudar\n");

  int ret = bid->result;
  th->ptr = NULL;
  free(bid);

  END_CRITICAL
  return ret;
}

double nAdjudicar(nSubasta s, int *punid)
{
  START_CRITICAL

  if (s == NULL) {
    if (punid != NULL)
      *punid = 0;
    END_CRITICAL
    return 0.0;
  }

  if (!s->closed) {
    int sold = s->waiting;
    s->closed = TRUE;
    s->total = 0.0;

    while (s->bids != NULL) {
      Bid *bid = s->bids;
      s->bids = bid->next;
      s->waiting--;
      bid->next = NULL;
      bid->result = TRUE;
      s->total += bid->offer;
      setReady(bid->th);
    }

    s->unsold = s->units - sold;
  }

  if (punid != NULL)
    *punid = s->unsold;

  double total = s->total;
  END_CRITICAL
  return total;
}

void nDestruirSubasta(nSubasta s)
{
  START_CRITICAL

  if (s != NULL) {
    if (s->bids != NULL)
      nFatalError("nDestruirSubasta", "Hay ofertas pendientes al destruir\n");
    free(s);
  }

  END_CRITICAL
}

